import React, { useState } from "react";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { analyzeImage } from "./api";
import { ClipLoader } from "react-spinners";

function UploadImage() {
  const [file, setFile] = useState(null);
  const [report, setReport] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [age, setAge] = useState("");
  const [sex, setSex] = useState("");

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (!selectedFile) return;

    if (!selectedFile.type.startsWith("image/")) {
      setError("Please upload an image file (JPEG/PNG/DICOM)");
      return;
    }

    setFile(selectedFile);
    setError("");
    setReport("");
  };

  const handleUpload = async () => {
    if (!file) {
      setError("Please select an image file");
      return;
    }

    if (!age || !sex) {
      setError("Please provide patient age and sex");
      return;
    }

    setLoading(true);
    setError("");
    setReport("");

    try {
      const formData = new FormData();
      formData.append("file", file);
      formData.append("age", age);
      formData.append("sex", sex);

      const data = await analyzeImage(formData);

      if (data?.analysis) {
        setReport(data.analysis);
      } else {
        setError(data?.detail || "Failed to analyze image");
      }
    } catch (err) {
      console.error("Analysis error:", err);
      setError(err.message || "Image analysis failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-6 bg-white dark:bg-gray-800 rounded-xl shadow-2xl w-full max-w-3xl mx-auto">
      <h2 className="text-3xl font-bold mb-8 text-center text-gray-800 dark:text-gray-100">
        Medical Image Analysis
      </h2>

      <div className="space-y-6">
        {/* File Upload Section */}
        <div className="space-y-3">
          <label className="block text-lg font-medium text-gray-700 dark:text-gray-300">
            Upload Medical Scan
          </label>
          <input
            type="file"
            onChange={handleFileChange}
            accept="image/*,.dcm"
            className="block w-full text-gray-600 dark:text-gray-300 file:mr-4 file:py-3 file:px-6 file:rounded-xl file:border-0 file:text-lg file:font-semibold file:bg-blue-600 file:text-white hover:file:bg-blue-700 dark:file:bg-blue-700 dark:hover:file:bg-blue-800 transition-colors"
          />
        </div>

        {/* Patient Information */}
        <div className="grid grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
              Patient Age
            </label>
            <input
              type="number"
              value={age}
              onChange={(e) => setAge(e.target.value.replace(/[^0-9]/g, ''))}
              className="w-full p-3 border-2 rounded-lg bg-white dark:bg-gray-700 border-gray-200 dark:border-gray-600 text-gray-800 dark:text-gray-100 focus:ring-2 focus:ring-blue-500"
              placeholder="35"
              min="0"
              max="120"
            />
          </div>
          <div className="space-y-2">
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
              Biological Sex
            </label>
            <select
              value={sex}
              onChange={(e) => setSex(e.target.value)}
              className="w-full p-3 border-2 rounded-lg bg-white dark:bg-gray-700 border-gray-200 dark:border-gray-600 text-gray-800 dark:text-gray-100 focus:ring-2 focus:ring-blue-500"
            >
              <option value="">Select...</option>
              <option value="Male">Male</option>
              <option value="Female">Female</option>
              <option value="Other">Other</option>
            </select>
          </div>
        </div>

        {/* Analyze Button */}
        <button
          onClick={handleUpload}
          disabled={loading}
          className={`w-full py-4 px-8 rounded-xl font-bold text-white text-lg transition-colors ${
            loading ? 'bg-gray-400' : 'bg-blue-600 hover:bg-blue-700 dark:bg-blue-700 dark:hover:bg-blue-800'
          }`}
        >
          {loading ? (
            <div className="flex items-center justify-center gap-3">
              <ClipLoader color="#ffffff" size={26} />
              <span>Analyzing Image...</span>
            </div>
          ) : (
            'Start Analysis'
          )}
        </button>

        {/* Error Display */}
        {error && (
          <div className="p-4 bg-red-100 dark:bg-red-900 text-red-700 dark:text-red-100 rounded-lg flex items-center gap-3">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
            {error}
          </div>
        )}

        {/* Analysis Results */}
        {report && (
          <div className="mt-8 bg-gray-50 dark:bg-gray-700 p-8 rounded-xl shadow-inner">
            <h3 className="text-2xl font-bold mb-6 text-gray-800 dark:text-gray-100 border-b pb-4 border-gray-200 dark:border-gray-600">
              Analysis Report
            </h3>
            <div className="prose dark:prose-invert max-w-none">
              <ReactMarkdown
                remarkPlugins={[remarkGfm]}
                components={{
                  strong({ node, children }) {
                    return <strong className="text-blue-600 dark:text-blue-400">{children}</strong>;
                  },
                  h3({ node, children }) {
                    return <h3 className="text-xl font-semibold mt-8 mb-4 text-gray-800 dark:text-gray-100">{children}</h3>;
                  }
                }}
              >
                {report}
              </ReactMarkdown>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default UploadImage;
